+/**
+ * V3 Federation Types
+ *
+ * Multi-cluster coordination and synchronization types aligned with agentic-flow@alpha:
+ * - Federation hub for cross-cluster sync
+ * - Vector clock conflict resolution
+ * - Ephemeral agent management
+ * - Multi-tenant support
+ *
+ * Performance Targets:
+ * - Sync latency: <50ms
+ * - Conflict detection: <5ms
+ * - Vector clock update: <1ms
+ */
+
+// ============================================================================
+// Federation Hub Types
+// ============================================================================
+
+/**
+ * Federation hub configuration
+ */
+export interface FederationHubConfig {
+  /** Hub endpoint (quic://host:port) */
+  endpoint: string;
+
+  /** Agent identifier */
+  agentId: string;
+
+  /** Tenant identifier */
+  tenantId: string;
+
+  /** JWT authentication token */
+  token: string;
+
+  /** Enable mTLS */
+  enableMTLS?: boolean;
+
+  /** Certificate path */
+  certPath?: string;
+
+  /** Key path */
+  keyPath?: string;
+
+  /** CA path */
+  caPath?: string;
+
+  /** Sync interval in ms */
+  syncInterval?: number;
+
+  /** Conflict resolution strategy */
+  conflictResolution?: ConflictResolutionStrategy;
+}
+
+/**
+ * Conflict resolution strategies
+ */
+export type ConflictResolutionStrategy =
+  | 'last-write-wins'
+  | 'first-write-wins'
+  | 'custom'
+  | 'merge';
+
+// ============================================================================
+// Vector Clock Types
+// ============================================================================
+
+/**
+ * Vector clock for conflict detection
+ */
+export interface VectorClock {
+  /** Map of agent ID to timestamp */
+  [agentId: string]: number;
+}
+
+/**
+ * Clock comparison result
+ */
+export type ClockComparison = 'before' | 'after' | 'concurrent' | 'equal';
+
+// ============================================================================
+// Sync Types
+// ============================================================================
+
+/**
+ * Sync message types
+ */
+export type SyncMessageType = 'pull' | 'push' | 'ack' | 'nack';
+
+/**
+ * Sync message
+ */
+export interface SyncMessage {
+  /** Message type */
+  type: SyncMessageType;
+
+  /** Source agent ID */
+  agentId: string;
+
+  /** Tenant ID */
+  tenantId: string;
+
+  /** Vector clock */
+  vectorClock: VectorClock;
+
+  /** Message timestamp */
+  timestamp: number;
+
+  /** Data payload (for push) */
+  data?: SyncUpdate[];
+
+  /** Request ID */
+  requestId?: string;
+}
+
+/**
+ * Sync update operation
+ */
+export type SyncOperation = 'insert' | 'update' | 'delete';
+
+/**
+ * Sync update record
+ */
+export interface SyncUpdate {
+  /** Record ID */
+  id: string;
+
+  /** Operation type */
+  operation: SyncOperation;
+
+  /** Record data */
+  data?: Record<string, unknown>;
+
+  /** Vector clock at time of update */
+  vectorClock: VectorClock;
+
+  /** Timestamp */
+  timestamp: number;
+}
+
+/**
+ * Sync result
+ */
+export interface SyncResult {
+  /** Whether sync was successful */
+  success: boolean;
+
+  /** Number of records pulled */
+  pullCount: number;
+
+  /** Number of records pushed */
+  pushCount: number;
+
+  /** Number of conflicts detected */
+  conflictCount: number;
+
+  /** Conflicts that were resolved */
+  resolvedConflicts: ConflictInfo[];
+
+  /** Sync duration in ms */
+  durationMs: number;
+
+  /** New vector clock after sync */
