+}
+
+/**
+ * Conflict information
+ */
+export interface ConflictInfo {
+  /** Record ID */
+  recordId: string;
+
+  /** Local version */
+  localVersion: SyncUpdate;
+
+  /** Remote version */
+  remoteVersion: SyncUpdate;
+
