+export interface IFederationHub {
+  /** Connect to the hub */
+  connect(): Promise<void>;
+
+  /** Disconnect from the hub */
+  disconnect(): Promise<void>;
+
+  /** Synchronize with the hub */
+  sync(db: unknown): Promise<SyncResult>;
+
