+    let totalWeight = 0;
+    for (let i = 0; i < trajectory.steps.length; i++) {
+      const weight = (i + 1 + index) / (trajectory.steps.length + index);
+      totalWeight += weight;
+      for (let j = 0; j < dim; j++) {
+        embedding[j] += trajectory.steps[i].stateAfter[j] * weight;
+      }
+    }
+
+    for (let j = 0; j < dim; j++) {
+      embedding[j] /= totalWeight;
+    }
+
+    return embedding;
+  }
