+ * Type for a deeply mocked interface (including nested objects)
+ */
+export type DeepMockedInterface<T> = {
+  [K in keyof T]: T[K] extends (...args: infer A) => infer R
+    ? MockInstance<(...args: A) => R>
+    : T[K] extends object
+    ? DeepMockedInterface<T[K]>
+    : T[K];
