+      // In hierarchical, connect workers to leader
+      const leader = this.getLeader();
+      if (leader && agent.role !== 'leader') {
+        this.connections.push({
+          from: agent.id,
+          to: leader.id,
+          type: 'leader'
+        });
+      }
+    }
+  }
+
+  private getDefaultCapabilities(type: string): string[] {
