+      tester: ['test', 'validate', 'e2e'],
+      reviewer: ['review', 'analyze', 'security-audit'],
+      coordinator: ['coordinate', 'manage', 'orchestrate'],
+      designer: ['design', 'prototype'],
+      deployer: ['deploy', 'release']
+    };
+    return defaults[type] || [];
+  }
+}
